<?php
declare(strict_types=1);
if($path!=='/admin/report-schedules')return;
if(!(user()['is_admin']??false)){http_response_code(403);exit('Forbidden');}
if($method==='POST'){verify_csrf();$action=(string)post('action');$id=(int)post('schedule_id');if($action==='toggle'){$q=db()->prepare('UPDATE scheduled_reports SET active=NOT active WHERE id=?');$q->execute([$id]);audit('toggle','scheduled_report',$id);flash('success','Report schedule updated.');redirect('/admin/report-schedules');}$type=in_array(post('report_type'),['weekly_pipeline','monthly_new_contacts'],true)?post('report_type'):'weekly_pipeline';$emails=array_values(array_unique(array_filter(array_map('trim',preg_split('/[,;\r\n]+/',(string)post('recipient_emails'))),fn($email)=>filter_var($email,FILTER_VALIDATE_EMAIL))));if(!$emails){flash('error','Enter at least one valid recipient email address.');redirect('/admin/report-schedules');}$time=preg_match('/^([01]\d|2[0-3]):[0-5]\d$/',(string)post('send_time'))?(string)post('send_time'):'08:00';$weekday=$type==='weekly_pipeline'?max(1,min(7,(int)post('weekday'))):null;$timezone=app_setting('app_timezone','America/New_York');$next=scheduled_report_next_run($type,$weekday,$time,$timezone);db()->prepare('INSERT INTO scheduled_reports(name,report_type,recipient_emails,weekday,send_time,timezone,next_run_at,created_by) VALUES(?,?,?,?,?,?,?,?)')->execute([trim((string)post('name'))?:($type==='weekly_pipeline'?'Weekly pipeline':'Month-end new contacts'),$type,implode(',',$emails),$weekday,$time.':00',$timezone,$next->format('Y-m-d H:i:s'),user()['id']]);audit('create','scheduled_report',(int)db()->lastInsertId(),['report_type'=>$type,'recipients'=>$emails,'next_run_at'=>$next->format('Y-m-d H:i:s')]);flash('success','Recurring report scheduled.');redirect('/admin/report-schedules');}
$rows=db()->query('SELECT * FROM scheduled_reports ORDER BY active DESC,next_run_at')->fetchAll();layout('Scheduled reports',function()use($rows){?><div class="actions"><h1 style="margin:0">Scheduled reports</h1><span class="spacer"></span><a class="btn secondary" href="/reports">Report builder</a></div><form class="card" method="post"><input type="hidden" name="_csrf" value="<?=csrf()?>"><h2>Schedule a recurring report</h2><div class="form-grid"><label>Schedule name<input name="name" placeholder="Executive pipeline email"></label><label>Report type<select name="report_type" id="scheduled-report-type"><option value="weekly_pipeline">Weekly pipeline report</option><option value="monthly_new_contacts">Month-end new contacts across all users</option></select></label><label>Recipients<input name="recipient_emails" placeholder="admin@example.com, sales@example.com" required><span class="muted">Separate multiple addresses with commas.</span></label><label id="scheduled-weekday">Day of week<select name="weekday"><option value="1">Monday</option><option value="2">Tuesday</option><option value="3">Wednesday</option><option value="4">Thursday</option><option value="5">Friday</option><option value="6">Saturday</option><option value="7">Sunday</option></select></label><label>Delivery time<input type="time" name="send_time" value="08:00" required><span class="muted"><?=e(app_setting('app_timezone','America/New_York'))?></span></label></div><p class="muted">Month-end reports run on the last calendar day at the selected time and include contacts created during that month.</p><button>Create schedule</button></form><div class="card"><h2>Recurring schedules</h2><table><thead><tr><th>Schedule</th><th>Recipients</th><th>Next delivery</th><th>Last result</th><th></th></tr></thead><tbody><?php foreach($rows as $r):?><tr><td><strong><?=e($r['name'])?></strong><br><?=e($r['report_type']==='weekly_pipeline'?'Weekly pipeline':'Month-end new contacts')?></td><td><?=e(str_replace(',',', ',$r['recipient_emails']))?></td><td><?=e($r['active']?$r['next_run_at'].' '.$r['timezone']:'Disabled')?></td><td><?=e($r['last_status'])?><?php if($r['last_error']):?><br><span class="danger-text"><?=e($r['last_error'])?></span><?php endif?></td><td><form method="post"><input type="hidden" name="_csrf" value="<?=csrf()?>"><input type="hidden" name="action" value="toggle"><input type="hidden" name="schedule_id" value="<?=$r['id']?>"><button class="compact <?=$r['active']?'danger':'secondary'?>"><?=$r['active']?'Disable':'Enable'?></button></form></td></tr><?php endforeach?></tbody></table><?php if(!$rows):?><p class="muted">No recurring reports are scheduled.</p><?php endif?></div><script>const type=document.querySelector('#scheduled-report-type'),weekday=document.querySelector('#scheduled-weekday');function toggleWeekday(){weekday.hidden=type.value!=='weekly_pipeline'}type.onchange=toggleWeekday;toggleWeekday()</script><?php });exit;

